// REUSABLE INPUT VALIDATION & SANITIZATION PATTERN
// Copy this entire function into any workflow that needs standardized input validation

function sanitizeInput(data) {
  if (typeof data !== 'object' || data === null) return {};

  const sanitized = {};
  for (const [key, value] of Object.entries(data)) {
    // Prevent prototype pollution attacks
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') continue;

    // Recursively sanitize nested objects
    if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
      sanitized[key] = sanitizeInput(value);
    } 
    // Sanitize arrays
    else if (Array.isArray(value)) {
      sanitized[key] = value.map(item => 
        typeof item === 'object' && item !== null ? sanitizeInput(item) :\
        typeof item === 'string' ? sanitizeString(item) :\
        item
      );
    }
    // Sanitize strings
    else if (typeof value === 'string') {
      sanitized[key] = sanitizeString(value);
    }
    // Leave other types (numbers, booleans, null) unchanged
    else {
      sanitized[key] = value;
    }
  }
  return sanitized;
}

function sanitizeString(str) {
  // Prevent XSS and injection attacks
  return String(str)
    .replace(/[<>&'"]/g, char => ({
      '<': '<',
      '>': '>',
      '&': '&',
      '"': '"',
      "'": '''
    }[char]))
    .trim();
}

// VALIDATION RULES CONFIGURATION - CUSTOMIZE PER WORKFLOW
// Define your validation rules here as an array of rule objects
const validationRules = [
  // EXAMPLE RULES (customize these for your specific workflow):
  // { name: 'fieldName', required: true/false, type: 'string|number|boolean|object|array', minLength: X, maxLength: Y, pattern: /regex/, enum: ['val1', 'val2'] }

  // Add your specific validation rules here:
  // Example for a chat message workflow:
  // { name: 'message', required: true, type: 'string', minLength: 1, maxLength: 1000 },
  // { name: 'userId', required: false, type: 'string', pattern: /^[a-zA-Z0-9_-]+$/ },
  // { name: 'email', required: false, type: 'string', pattern: /^[^@\s]+@[^@\s]+\.[^@\s]+$/ },
  // { name: 'phone', required: false, type: 'string', pattern: /^[\+]?[\d\s\-\(\)]+$/ },
  // { name: 'age', required: false, type: 'number', min: 0, max: 150 },
];

// MAIN VALIDATION LOGIC
const body = $json["body"] || {};
const sanitizedBody = sanitizeInput(body);
const errors = [];

// Check each validation rule
validationRules.forEach(rule => {
  const value = sanitizedBody[rule.name];

  // Check if required field is missing
  if (rule.required && (value === undefined || value === null || value === '')) {
    errors.push({
      field: rule.name,
      message: `Missing required field: ${rule.name}`,
      code: 'MISSING_FIELD'
    });
    return;
  }

  // Skip further validation if field is empty and not required
  if ((value === undefined || value === null || value === '') && !rule.required) {
    return;
  }

  // Type validation
  if (rule.type) {
    let typeValid = false;

    switch (rule.type) {
      case 'string':
        typeValid = typeof value === 'string';
        break;
      case 'number':
        typeValid = typeof value === 'number' && !isNaN(value);
        // Also accept numeric strings
        if (!typeValid && typeof value === 'string' && !isNaN(parseFloat(value)) && isFinite(value)) {
          typeValid = true;
          // Convert string number to actual number
          sanitizedBody[rule.name] = parseFloat(value);
        }
        break;
      case 'boolean':
        typeValid = typeof value === 'boolean' || 
                   (typeof value === 'string' && (value === 'true' || value === 'false')) ||
                   (typeof value === 'number' && (value === 0 || value === 1));
        // Normalize boolean values
        if (typeValid && typeof value !== 'boolean') {
          if (typeof value === 'string') {
            sanitizedBody[rule.name] = value.toLowerCase() === 'true' || value === '1' || value === 1;
          } else if (typeof value === 'number') {
            sanitizedBody[rule.name] = value === 1 || value === true;
          }
        }
        break;
      case 'object':
        typeValid = typeof value === 'object' && value !== null && !Array.isArray(value);
        break;
      case 'array':
        typeValid = Array.isArray(value);
        break;
      default:
        typeValid = typeof value === rule.type;
    }

    if (!typeValid) {
      errors.push({
        field: rule.name,
        message: `Field '${rule.name}' must be of type ${rule.type}`,
        code: 'INVALID_TYPE'
      });
      return;
    }
  }

  // String length validation
  if (rule.type === 'string' && typeof value === 'string') {
    if (rule.minLength !== undefined && value.length < rule.minLength) {
      errors.push({
        field: rule.name,
        message: `Field '${rule.name}' must be at least ${rule.minLength} characters long`,
        code: 'TOO_SHORT'
      });
      return;
    }
    if (rule.maxLength !== undefined && value.length > rule.maxLength) {
      errors.push({
        field: rule.name,
        message: `Field '${rule.name}' must not exceed ${rule.maxLength} characters`,
        code: 'TOO_LONG'
      });
      return;
    }
  }

  // Numeric range validation
  if (rule.type === 'number' && typeof value === 'number') {
    if (rule.min !== undefined && value < rule.min) {
      errors.push({
        field: rule.name,
        message: `Field '${rule.name}' must be at least ${rule.min}`,
        code: 'TOO_SMALL'
      });
      return;
    }
    if (rule.max !== undefined && value > rule.max) {
      errors.push({
        field: rule.name,
        message: `Field '${rule.name}' must not exceed ${rule.max}`,
        code: 'TOO_LARGE'
      });
      return;
    }
  }

  // Pattern validation (regex)
  if (rule.pattern && typeof value === 'string' && !rule.pattern.test(value)) {
    errors.push({
      field: rule.name,
      message: `Field '${rule.name}' has invalid format`,
      code: 'INVALID_FORMAT'
    });
    return;
  }

  // Enum validation
  if (rule.rule && Array.isArray(rule.enum) && rule.enum.length > 0) {
    if (!rule.enum.includes(value)) {
      errors.push({
        field: rule.name,
        message: `Field '${rule.name}' must be one of: ${rule.enum.join(', ')}`,
        code: 'INVALID_ENUM_VALUE'
      });
      return;
    }
  }
});

// Return errors if any found
if (errors.length > 0) {
  return [{
    json: {
      error: 'Validation failed',
      validationErrors: errors,
      failedAt: new Date().toISOString(),
      failedAtStep: 'Input Validation',
      inputData: $json
    },
    error: true
  }];
}

// Return sanitized data if validation passes
return [{ json: sanitizedBody }];
